// Ngân hàng nội dung "Luyện giao tiếp hàng ngày" — số hoá từ các sơ đồ tư duy
// kiểu Oxford Children's Picture Dictionary: mỗi chủ đề xoay quanh 1 mẫu câu
// (pattern) trung tâm, với 10 tình huống hội thoại xung quanh (Q của người
// đối diện — A là câu bé cần luyện nói). Phong cách Feynman: mỗi chủ đề luôn
// có "công thức" + "giải thích ngắn gọn dễ hiểu" đi kèm.

export interface FormulaLine {
  label: string;
  text: string;
}

export interface CommItem {
  id: string;
  icon: string;
  term: string;
  termIpa: string;
  termMeaning: string;
  question: string;
  questionIpa: string;
  questionMeaning: string;
  answer: string;
  /** Phiên âm IPA từng từ của "answer", cách nhau bằng dấu cách — số từ phải
   * khớp với answer.split(" ") để ghép đúng vào từng WordChip khi luyện đọc. */
  answerIpa: string;
  answerMeaning: string;
}

export interface CommTopic {
  id: string;
  icon: string;
  title: string;
  titleVi: string;
  color: string;
  pattern: string;
  patternMeaning: string;
  formula: FormulaLine[];
  explanation: string;
  tip: string;
  items: CommItem[];
}

